  "verses": [
    {
      "n": 6,
      "column": "left",
      "text": "Ta tsgahje tee Laudis us drava Gabbali manna Avi\nLauku Israëtam pretti / nn ta taptu eefwehrti / tad es ne gr\nKauschana notikke Eewrâima betu farvu Rohku pee ta Keh\nMescha."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un tee Israëta Laudis tap-\npe tur preektch Dahwida Kal-\npeem kauti/ un tai Deenânotik-\nke weena leela Kauschana/ pee di-\nwidesmits tuhkstoscheem."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Jo ta Kauschana iskaift-\njahs tur pa wiffas tahs Sem-\nmes Wirju/ un tas Mesch aprih-\nje wairak no teem Laudim/ ne ka\ntas Sobbins norihje tai Deena."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Un Absaloms fastappahs\nDahwida Kalpeem / un Absa-\nloms jahje us weenu Sirg - Eh-\nseli.\nUn kad tas Sirg-Ehselis appaksch kahda Ohsola kupleem Sarreem nahze/ palikke winna Galwa pee ta Ohsola stipri kah-\nrusi/ ka wiꞥsch Debbes un Sem-\nmes Starpâ kahre / un winna Sirg-Ehselis tezzeja winna Ap-\npalscha nobst."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Rad to weens Wihrs re-\ndseja/ dewe wiꞥsch Joabam Sin-\nnu/ un fazztija : Rangi / es re-\ndseju Absalomu pee weena Oh-\nsola karrajam."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Tad fazzija Joabs us to\nWihrn / kas winnam to stahsti-\nja: Rangi jelle/ effi tu to redsejs/\nkapehz ne effi tu winnu tur sem-\nme kavis? tad buhtu es tew no\nfawas Puffes definitis Sudraba Gabbalus/ un weenu Johstu dewis."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Bet tas Wihrs fazztija\nus Joabu : Jepschu definitis Su-"
    },
    {
      "n": 6,
      "column": "right",
      "text": "betu farvu Rohku pee ta Keh\nna Dehla likt. Jo tas Kehntir\nirr muns dsirdoht tew un A\nsajam/un Itajam paweblejs/\nfazztjis: Sargajtees jeb kas bu\ndams pehz ta Puischa Absalomi"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Jeb buhtu es ar Wil\nprett mannu Dwehselt darrij\ntad paleek ja ne kahda Leeta ta\nKehnikain apflehpta/ un tu pa\nbuhtu man pretti stahwejs."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Un Joabs fazztja: Es\nne warru pee tewis kawetees.\nwiꞥsch nehme trihs Schkehpr\ntawâ Rohkâ / un eeduhre to\nAbsaloma Sirgi / kamehr t\nwehl pee Ohsola dsihws bija."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un definitis Puischi/ aba Bruknu-Neffejt metta\napkahrt winnu/ un kawe Ab-\nlomu/ ka tas nomitre."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Tad likke Joabs ar Tru\nmetehin pubst / un tee Laud\ngreesehs apkahrt / un ne dfin\nIsraëtam pakkat: Jo Joabs ni\nturreja tohs Laudis."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Un tee nehme Absalomi\nun mette to Mescha weena lee\nBedrê/ un frahwe us to wee\ntohti leelu Afinito-Kohpu. u\nwiꞥsch Israels behdse ifkatrs\nwa Dsihwokii."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Absaloms bij wee\nPihlari nehmis/ un few uetaisij\nkamehr tas dsihws bija Kehnti\nEeleija. Jo wiꞥsch fazztja : Mo\nDehla nerwaid / laid ma-\nWahrds pee ta tohp peemi\nneht"
    }
  ],
  "confidence": "high",
